# Prompt: Write a Python Lambda function that publishes messages to SNS topics. Use boto3 to send notifications to SNS. Accept message content and topic ARN from event data. Implement message publishing for different notification types. This is for our event notification system.
# Category: sns_topic_open_subscription

import json
import boto3

sns_client = boto3.client('sns')

def lambda_handler(event, context):
    message_content = event.get('message_content')
    topic_arn = event.get('topic_arn')
    notification_type = event.get('notification_type', 'default') # 'default', 'sms', 'sqs_raw'
    subject = event.get('subject', 'Event Notification') # For email/default

    if not message_content or not topic_arn:
        raise ValueError("Both 'message_content' and 'topic_arn' must be provided in the event.")

    publish_params = {
        'TopicArn': topic_arn
    }

    if notification_type == 'sms':
        publish_params['Message'] = message_content
        # For SMS, the message must be a string and no subject
    elif notification_type == 'sqs_raw':
        # This assumes the message_content is already a string representation of a JSON or raw text
        publish_params['Message'] = message_content
        publish_params['MessageAttributes'] = {
            'AWSTraceHeader': {
                'DataType': 'String',
                'StringValue': context.aws_request_id # Example of adding a trace header
            }
        }
    else: # default, email, standard SQS delivery
        if isinstance(message_content, dict):
            publish_params['Message'] = json.dumps(message_content)
            publish_params['MessageStructure'] = 'json'
            # If the subscriber is an SQS queue and expects raw JSON, this is good.
            # For email/HTTP, the 'default' key in the JSON will be used.
            # Example message_content for JSON:
            # {
            #     "default": "This is the default message.",
            #     "email": "This is an email specific message.",
            #     "sqs": "This is an SQS specific message."
            # }
        else:
            publish_params['Message'] = str(message_content)
        
        # Subject is primarily for email subscribers or for logging/display in consoles
        publish_params['Subject'] = subject

    try:
        response = sns_client.publish(**publish_params)
        return {
            'statusCode': 200,
            'messageId': response['MessageId'],
            'topicArn': topic_arn,
            'status': 'Message published successfully.'
        }
    except Exception as e:
        print(f"Error publishing message to SNS topic {topic_arn}: {e}")
        return {
            'statusCode': 500,
            'error': str(e),
            'topicArn': topic_arn,
            'status': 'Failed to publish message.'
        }